import React, { useState, useEffect } from 'react';

// Definimos los tipos para el estado de tiempo restante
interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

interface CountdownProps {
  day: string; // La fecha objetivo debe ser un string en formato ISO
}

const Count: React.FC<CountdownProps> = ({ day }) => {
  // Estado para el contador con el tipo `TimeLeft`
  const [timeLeft, setTimeLeft] = useState<TimeLeft>(calculateTimeLeft(day));

  // Calcula la diferencia entre la fecha futura y la fecha actual
  function calculateTimeLeft(day: string): TimeLeft {
    const difference = new Date(day).getTime() - new Date().getTime();

    // Si ya pasó la fecha objetivo, no hay tiempo restante
    if (difference <= 0) {
      return {
        days: 0,
        hours: 0,
        minutes: 0,
        seconds: 0,
      };
    }

    // Calculamos días, horas, minutos y segundos
    const days = Math.floor(difference / (1000 * 60 * 60 * 24));
    const hours = Math.floor(
      (difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)
    );
    const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((difference % (1000 * 60)) / 1000);

    return { days, hours, minutes, seconds };
  }

  // Efecto para actualizar el contador cada segundo
  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft(day));
    }, 1000);

    // Limpiar el intervalo cuando el componente se desmonte
    return () => clearInterval(timer);
  }, [day]);

  // Renderiza el contador en formato días, horas, minutos y segundos
  return (
    <div>
      <h1>Cuenta atrás:</h1>
      <p>
        {timeLeft.days} días, {timeLeft.hours} horas, {timeLeft.minutes}{' '}
        minutos, {timeLeft.seconds} segundos
      </p>
    </div>
  );
};

export default Count;
